negativeExample:
package org.eclipse.jdt.core;
public interface IJavaProject {}

package org.eclipse.jdt.internal.ui.text.java.hover;
import org.eclipse.jdt.core.IJavaProject;
public class JavadocHover {
    public static final String CONSTANT_VALUE_SEPARATOR = " : ";
    public static String someOtherStaticMethod() {
        return "something else";
    }
}

package test;
import org.eclipse.jdt.core.IJavaProject;
import org.eclipse.jdt.internal.ui.text.java.hover.JavadocHover;

public class MyConsumerClass {
    public void someMethod(IJavaProject project) {
        StringBuffer label = new StringBuffer();
        label.append("Field");
        label.append(JavadocHover.CONSTANT_VALUE_SEPARATOR); // Should not match (already the target)
        label.append(JavadocHover.someOtherStaticMethod()); // Should not match (different method)
        label.append("someValue");
        System.out.println(label.toString());
    }
}
